import{_ as s,o as a,c as t,a2 as n}from"./chunks/framework.DtwafDNl.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/index.md","filePath":"architecture/index.md"}'),i={name:"architecture/index.md"};function o(r,e,d,c,l,p){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Callytics is a self-hosted call-center stack built around Asterisk, a Stasis call execution service, a NestJS backend, PostgreSQL, Redis, and a React frontend. Asterisk handles SIP and media, Stasis runs the active call logic, the backend owns the management API and operational features, PostgreSQL stores durable data, Redis carries live events and short-lived state, and the frontend gives you the browser interface.</p><p>You design and publish flows in the browser. The backend stores and prepares that configuration, and new calls are executed by Stasis against the published flow state — no manual dialplan editing required.</p><h3 id="container-topology" tabindex="-1">Container topology <a class="header-anchor" href="#container-topology" aria-label="Permalink to &quot;Container topology&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                      host network                       │</span></span>
<span class="line"><span>│                                                         │</span></span>
<span class="line"><span>│  ┌─────────────┐   ARI :8088   ┌─────────────┐          │</span></span>
<span class="line"><span>│  │  asterisk   │◄─────────────►│   stasis    │          │</span></span>
<span class="line"><span>│  │  SIP :5080  │   AMI :5038   │             │          │</span></span>
<span class="line"><span>│  │  RTP 10000- │◄──────────────│             │          │</span></span>
<span class="line"><span>│  │  20000      │               └──────┬──────┘          │</span></span>
<span class="line"><span>│  └─────────────┘                      │                 │</span></span>
<span class="line"><span>│                                       │ Redis :6380     │</span></span>
<span class="line"><span>│  ┌─────────────┐                      │                 │</span></span>
<span class="line"><span>│  │   backend   │◄─────────────────────┘                 │</span></span>
<span class="line"><span>│  │   :3001     │                                        │</span></span>
<span class="line"><span>│  └──────┬──────┘                                        │</span></span>
<span class="line"><span>│         │ :5432 PostgreSQL                              │</span></span>
<span class="line"><span>│         │ :6380 Redis                                   │</span></span>
<span class="line"><span>└─────────┼───────────────────────────────────────────────┘</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>    ┌─────▼──────┐    ┌─────────────┐    ┌─────────────┐</span></span>
<span class="line"><span>    │  postgres  │    │    redis    │    │  frontend   │</span></span>
<span class="line"><span>    │  :5432     │    │  :6380      │    │  :3000      │</span></span>
<span class="line"><span>    │  (bridge)  │    │  (bridge)   │    │  (bridge)   │</span></span>
<span class="line"><span>    └────────────┘    └─────────────┘    └─────────────┘</span></span></code></pre></div><h2 id="service-breakdown" tabindex="-1">Service Breakdown <a class="header-anchor" href="#service-breakdown" aria-label="Permalink to &quot;Service Breakdown&quot;">​</a></h2><p><strong>Asterisk</strong> is the telephony engine. It accepts SIP traffic on port <code>5080</code>, handles RTP media, manages bridges and recordings, and exposes two control interfaces: ARI plus WebRTC WebSocket transport on <code>127.0.0.1:8088</code>, and AMI on <code>127.0.0.1:5038</code>.</p><p><strong>Stasis</strong> is the call execution runtime. It connects to Asterisk over ARI WebSocket, receives live <code>StasisStart</code> events, loads the published call flow, walks each node, sends ARI commands back to Asterisk, and publishes timeline and telemetry events to Redis.</p><p><strong>NestJS backend</strong> serves the management API on port <code>3001</code>, handles configuration for extensions, trunks, flows, campaigns, firewall, VPN, backups, diagnostics, and recordings, subscribes to Redis pub/sub channels, and relays real-time events to the browser over Socket.IO.</p><p><strong>PostgreSQL</strong> stores all durable data: flows, flow versions, extensions, trunks, inbound routes, call logs, recordings metadata, campaigns, operators, queues, firewall rules, and backups. Bound to <code>127.0.0.1:5432</code>.</p><p><strong>Redis</strong> is the live event and coordination layer. It runs on <code>127.0.0.1:6380</code> on the host (mapped from container port <code>6379</code>) and carries telemetry between Stasis and the backend, queue and operator state, campaign coordination, SIP capture data, and short-lived runtime state.</p><p><strong>Frontend</strong> is the React browser application. It connects to the backend on port <code>3001</code>, uses Socket.IO for real-time updates across all live pages, and can also host the in-browser WebRTC softphone for operator extensions.</p><h2 id="why-host-networking" tabindex="-1">Why Host Networking <a class="header-anchor" href="#why-host-networking" aria-label="Permalink to &quot;Why Host Networking&quot;">​</a></h2><p>ARI communicates over <code>127.0.0.1:8088</code> and AMI over <code>127.0.0.1:5038</code>. Both are loopback addresses on the host. If Stasis or the backend ran on a Docker bridge network, they could not reach these loopback addresses — bridge containers see a different network namespace.</p><p>SIP binds on <code>0.0.0.0:5080</code>, not the default <code>5060</code>, because the host machine typically already occupies port <code>5060</code> with a system SIP service or another process. Using <code>5080</code> avoids that conflict.</p><p>Host networking also means Asterisk, Stasis, and the backend all share the same network namespace. RTP media and SIP signaling bind directly to the host&#39;s network interfaces, avoiding the bridge and NAT translation problems that commonly break SIP audio paths in Docker setups.</p><p>For the browser softphone, the backend regenerates the WebRTC transport config on startup. That config binds the WebSocket transport on port <code>8088</code>, enables ICE support, and auto-discovers Docker bridge subnets so Asterisk writes the correct <code>local_net</code> entries for WebRTC RTP negotiation.</p><p>The optional WireGuard VPN container is different: it terminates VPN tunnels rather than owning SIP/RTP sockets, so it can run on a bridge network and publish only UDP port <code>51820</code>.</p><h2 id="call-execution-path" tabindex="-1">Call Execution Path <a class="header-anchor" href="#call-execution-path" aria-label="Permalink to &quot;Call Execution Path&quot;">​</a></h2><ol><li>Inbound SIP INVITE arrives at Asterisk on port <code>5080</code></li><li>Asterisk matches the DID in <code>extensions_callytics_inbound.conf</code> — auto-generated by the backend whenever inbound routes change</li><li>Asterisk sends the channel to the Stasis app named <code>callytics</code></li><li>Stasis <code>StasisStart</code> fires — checks if <code>channelExten</code> starts with <code>#</code> (direct outbound) or is a DID (inbound flow)</li><li>For inbound: Stasis calls <code>GET /inbound-routes?did=&lt;DID&gt;</code> on the backend to resolve the flow ID</li><li>Stasis fetches flow nodes and edges, answers the channel, creates an ARI bridge of type <code>mixing,dtmf_events</code>, runs <code>runFlow()</code></li><li><code>runFlow()</code> is an in-memory loop — <code>CallSession</code> tracks <code>currentNodeKey</code>, follows edges after each node result</li><li>Already-running calls keep their in-memory session — saving a flow affects subsequent calls only</li><li>Stasis publishes events to Redis pub/sub as the call progresses</li><li>Backend subscribes to Redis, writes durable records to PostgreSQL, relays real-time updates to browser via Socket.IO</li></ol><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Phone</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Asterisk</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Stasis</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Backend</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Redis</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant Browser</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Phone-&gt;&gt;Asterisk: SIP INVITE :5080</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Asterisk-&gt;&gt;Stasis: StasisStart (ARI)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Stasis-&gt;&gt;Backend: GET /inbound-routes?did=1234</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Backend--&gt;&gt;Stasis: flowId</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Stasis-&gt;&gt;Asterisk: answer + create bridge</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    loop runFlow()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Stasis-&gt;&gt;Asterisk: node commands (play, digits, transfer...)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Asterisk--&gt;&gt;Stasis: ARI events</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    end</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Stasis-&gt;&gt;Redis: publish call events</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Redis--&gt;&gt;Backend: subscribe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Backend--&gt;&gt;Browser: Socket.IO</span></span></code></pre></div><h2 id="redis-as-the-event-backbone" tabindex="-1">Redis as the Event Backbone <a class="header-anchor" href="#redis-as-the-event-backbone" aria-label="Permalink to &quot;Redis as the Event Backbone&quot;">​</a></h2><p>Redis decouples call execution (Stasis) from durable storage and browser updates (backend). Stasis publishes fast operational events without knowing which consumers are listening. The backend subscribes and handles persistence and real-time relay independently.</p><h3 id="pub-sub-channels" tabindex="-1">Pub/sub channels <a class="header-anchor" href="#pub-sub-channels" aria-label="Permalink to &quot;Pub/sub channels&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Channel</th><th>Purpose</th></tr></thead><tbody><tr><td><code>callytics:call-events</code></td><td>Call started, answered, ended — written to call log</td></tr><tr><td><code>callytics:call-timeline</code></td><td>Node-by-node execution trace for the per-call timeline view</td></tr><tr><td><code>callytics:sip-status</code></td><td>SIP registration state and trunk status updates</td></tr><tr><td><code>callytics:sip-traffic</code></td><td>Parsed SIP messages from the AMI PJSIP logger for the capture page</td></tr><tr><td><code>callytics:sip-capture</code></td><td>Redis stream for raw tshark packets when <code>TSHARK_ENABLED=true</code></td></tr><tr><td><code>callytics:campaign:*</code></td><td>Campaign dial events, contact outcomes, window coordination</td></tr><tr><td><code>callytics:callback:*</code></td><td>Callback request events and execution coordination</td></tr></tbody></table><p>Redis also carries short-lived coordination state as keys:</p><ul><li><code>queue:&lt;id&gt;:operators</code> — set of ARI channel IDs for logged-in operators</li><li><code>operator:&lt;id&gt;:queue</code> — the queue ID the operator is currently logged into</li><li><code>operator:&lt;id&gt;:channel</code> — the operator&#39;s live ARI channel ID</li></ul><h2 id="real-time-updates" tabindex="-1">Real-Time Updates <a class="header-anchor" href="#real-time-updates" aria-label="Permalink to &quot;Real-Time Updates&quot;">​</a></h2><p>The full chain from a call event to the browser:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Stasis → Redis pub/sub → NestJS subscribes → Socket.IO → browser</span></span></code></pre></div><p>The backend subscribes to Redis channels on startup. When an event arrives it processes the payload, persists what needs persisting, then emits a Socket.IO event to connected browsers.</p><h3 id="socket-io-events-by-page" tabindex="-1">Socket.IO events by page <a class="header-anchor" href="#socket-io-events-by-page" aria-label="Permalink to &quot;Socket.IO events by page&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Page</th><th>Socket.IO events consumed</th></tr></thead><tbody><tr><td>Call Logs</td><td><code>call:event</code>, <code>call:timeline</code></td></tr><tr><td>Live Dashboard</td><td><code>call:event</code>, <code>queue:state</code>, <code>operator:state</code></td></tr><tr><td>Diagnostics</td><td><code>sip:status</code>, <code>sip:registration</code></td></tr><tr><td>SIP Capture</td><td><code>sip:traffic</code>, <code>sip:capture-packet</code></td></tr><tr><td>Campaigns</td><td><code>campaign:progress</code>, <code>campaign:contact-result</code></td></tr><tr><td>Firewall</td><td><code>firewall:event</code>, <code>firewall:block</code></td></tr></tbody></table>`,34)])])}const k=s(i,[["render",o]]);export{u as __pageData,k as default};
